import React, { useEffect, useState } from "react";
import { Table, Button, Tooltip, Select } from "antd";
import {
  Pencil,
  Search,
  Trash2,
  Plus,
  Package,
  Layers,
  ArrowUpDown,
  CheckCircle2,
  AlertCircle,
  ShieldCheck
} from "lucide-react";
import { useDispatch, useSelector } from "react-redux";
import { deleteAProduct, getProducts, updateProductStatus } from "../features/product/productSlice";
import { Link, useNavigate, useLocation } from "react-router-dom";
import CustomModal from "../components/CustomModal";

const Productlist = () => {
  const [open, setOpen] = useState(false);
  const [productId, setproductId] = useState("");
  const [searchText, setSearchText] = useState("");
  const navigate = useNavigate();
  const location = useLocation();

  const showModal = (e) => {
    setOpen(true);
    setproductId(e);
  };

  const hideModal = () => {
    setOpen(false);
  };

  const dispatch = useDispatch();
  useEffect(() => {
    dispatch(getProducts());
  }, [dispatch]);

  // Guard: ensure it's always an array regardless of Redux state shape
  const productState = useSelector((state) => {
    const raw = state?.product?.products;
    if (Array.isArray(raw)) return raw;
    if (raw?.data && Array.isArray(raw.data)) return raw.data;
    return [];
  });
  const user = useSelector((state) => state?.auth?.user);

  const columns = [
    {
      title: "Product Details",
      dataIndex: "title",
      render: (text, record) => (
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 rounded-xl bg-slate-50 border border-slate-100 flex items-center justify-center overflow-hidden flex-shrink-0 shadow-sm">
            <img
              src={record.photo}
              alt={text}
              className="w-full h-full object-cover"
            />
          </div>
          <div className="flex flex-col">
            <span className="font-bold text-black text-[16px] leading-tight">
              {text}
            </span>
            <span className="text-[13px] text-slate-500 font-medium mt-1">
              {record.id_short}
            </span>
            {record.prescriptionRequired && (
              <span className="bg-orange-50 text-orange-600 border border-orange-100 px-2 py-0.5 rounded-md text-[10px] font-bold uppercase w-fit mt-1.5 flex items-center gap-1">
                <AlertCircle size={10} /> Prescription Required
              </span>
            )}
          </div>
        </div>
      ),
    },
    {
      title: "Category",
      dataIndex: "category",
      render: (category) => (
        <div className="flex flex-col">
          <span className="text-black font-bold text-[15px]">{category}</span>
          <span className="text-[12px] text-slate-500 font-medium mt-0.5">
            Pharma Category
          </span>
        </div>
      ),
    },
    {
      title: "Price",
      dataIndex: "price",
      render: (price) => (
        <div className="flex items-baseline gap-1">
          <span className="font-bold text-black text-[16px]">
            {price.toLocaleString()}
          </span>
          <span className="text-[13px] text-slate-500 font-bold uppercase tracking-wider">
            ETB
          </span>
        </div>
      ),
    },
    {
      title: "Stock Status",
      dataIndex: "quantity",
      render: (quantity) => (
        <div className="flex flex-col">
          <div className="flex items-center gap-2">
            {quantity > 0 ? (
              <CheckCircle2 size={16} className="text-emerald-500" />
            ) : (
              <AlertCircle size={16} className="text-rose-500" />
            )}
            <span
              className={`text-[15px] font-bold ${quantity > 0 ? "text-black" : "text-rose-600"}`}
            >
              {quantity} In Stock
            </span>
          </div>
          <span className="text-[12px] text-slate-500 font-medium mt-1">
            {quantity > 10 ? "Optimal Level" : "Low Inventory"}
          </span>
        </div>
      ),
    },
    {
      title: "Compliance",
      dataIndex: "status",
      render: (status) => {
        const map = {
          approved: { cls: "ok", label: "Approved" },
          rejected: { cls: "err", label: "Rejected" },
        };
        const s = map[status] || { cls: "warn", label: "Pending" };
        return <span className={`vibe-pill ${s.cls}`}>{s.label}</span>;
      },
    },
    {
      title: "Actions",
      dataIndex: "action",
      render: (text, record) => (
        <div className="flex items-center gap-2">
          {location.pathname.includes("/superAdmin") && record.status === "pending" && (
            <Tooltip title="Verify & Approve">
              <Button
                type="text"
                icon={<ShieldCheck size={18} />}
                onClick={() => {
                  dispatch(updateProductStatus({ 
                    productId: record.key, 
                    ProductApproved: "Approved" 
                  })).then(() => {
                    dispatch(getProducts());
                  });
                }}
                className="text-emerald-500 hover:text-emerald-700 hover:bg-emerald-50 rounded-lg"
              />
            </Tooltip>
          )}
          <Tooltip title="Edit Product">
            <Button
              type="text"
              icon={<Pencil size={18} />}
              onClick={() => {
                const isAdmin = location.pathname.includes("/superAdmin");
                const basePath = isAdmin ? "/superAdmin" : "/admin";
                navigate(`${basePath}/product/${record.key}`);
              }}
              className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg"
            />
          </Tooltip>
          <Tooltip title="Delete Product">
            <Button
              type="text"
              icon={<Trash2 size={18} />}
              onClick={() => showModal(record.key)}
              className="text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg"
            />
          </Tooltip>
        </div>
      ),
    },
  ];

  const deleteProduct = (id) => {
    dispatch(deleteAProduct({ productId: id, userId: user?._id }));
    setOpen(false);
    setTimeout(() => {
      dispatch(getProducts());
    }, 100);
  };

  const data1 =
    productState?.map((product, i) => ({
      key: product.id || product._id,
      title: product.title,
      category: product.category,
      price: product.price,
      quantity: product.quantity,
      photo: 
        product?.images?.[0]?.secure_url || 
        product?.colors?.[0]?.images?.[0]?.secure_url ||
        `https://api.dicebear.com/7.x/shapes/svg?seed=${product.title}`,
      id_short: `PRD-${String(i + 1).padStart(3, "0")}`,
      prescriptionRequired: product.requiresPrescription || product.prescriptionRequired,
      status: product.status,
    })) || [];


  const filteredData = data1.filter(
    (p) =>
      p.title.toLowerCase().includes(searchText.toLowerCase()) ||
      p.category.toLowerCase().includes(searchText.toLowerCase()),
  );

  return (
    <div className="vibe-page space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <div className="flex items-center gap-2 mb-1">
            <div className="w-1 h-4 rounded-full" style={{ background: "var(--c-accent)" }} />
            <span className="text-[11px] font-bold uppercase tracking-widest" style={{ color: "var(--c-accent)" }}>Inventory</span>
          </div>
          <h1 className="text-[26px] font-bold" style={{ color: "var(--c-text-1)", margin: 0 }}>Product Inventory</h1>
          <p className="text-[14px] mt-1" style={{ color: "var(--c-text-3)" }}>Manage products and stock levels.</p>
        </div>
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="relative flex-1 sm:flex-none">
            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2" style={{ color: "var(--c-text-3)" }} />
            <input type="text" placeholder="Search products..." className="vibe-search sm:w-60" onChange={(e) => setSearchText(e.target.value)} />
          </div>
          <Link to="../product">
            <button className="vibe-btn-primary"><Plus size={18} /> Add Product</button>
          </Link>
        </div>
      </div>

      <div className="vibe-card">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center px-6 py-4 gap-3" style={{ borderBottom: "1px solid var(--c-border)" }}>
          <div className="flex items-center gap-3">
            <div className="vibe-icon" style={{ background: "var(--c-accent-bg)" }}>
              <Package size={18} style={{ color: "var(--c-accent)" }} />
            </div>
            <span className="font-bold text-[15px]" style={{ color: "var(--c-text-1)" }}>Product Catalogue</span>
            <span className="text-[13px]" style={{ color: "var(--c-text-3)" }}>{filteredData.length} items</span>
          </div>
          <Select
            defaultValue="new"
            style={{ width: 160 }}
            bordered={false}
            suffixIcon={<ArrowUpDown size={14} style={{ color: "var(--c-text-3)" }} />}
          >
            <Select.Option value="new">Newest First</Select.Option>
            <Select.Option value="price_low">Price: Low → High</Select.Option>
            <Select.Option value="price_high">Price: High → Low</Select.Option>
          </Select>
        </div>

        <Table
          columns={columns}
          dataSource={filteredData}
          pagination={{ pageSize: 10, showSizeChanger: false }}
          className="vibe-table"
          rowKey="key"
        />
      </div>

      <CustomModal
        hideModal={hideModal}
        open={open}
        performAction={() => deleteProduct(productId)}
        title="Delete Product"
        content="Are you sure you want to delete this product? This action cannot be undone."
      />
    </div>
  );
};

export default Productlist;
